@use '../core/style/elevation';
@use 'sass:map';
@use '../core/tokens/m2-utils';
@use '../core/tokens/m3-utils';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);

  @return (
    base: (
      menu-container-shape: 4px,
      menu-divider-bottom-spacing: 0,
      menu-divider-top-spacing: 0,
      menu-item-spacing: 16px,
      menu-item-icon-size: 24px,
      menu-item-leading-spacing: 16px,
      menu-item-trailing-spacing: 16px,
      menu-item-with-icon-leading-spacing: 16px,
      menu-item-with-icon-trailing-spacing: 16px,
      menu-container-elevation-shadow: elevation.get-box-shadow(8),

      // Unused
      menu-base-elevation-level: null,
    ),
    color: (
      menu-item-label-text-color: map.get($system, on-surface),
      menu-item-icon-color: map.get($system, on-surface),
      menu-item-hover-state-layer-color: m3-utils.color-with-opacity(
          map.get($system, on-surface), map.get($system, hover-state-layer-opacity)),
      menu-item-focus-state-layer-color: m3-utils.color-with-opacity(
          map.get($system, on-surface), map.get($system, focus-state-layer-opacity)),
      menu-container-color: map.get($system, surface),
      menu-divider-color: map.get($system, outline),
    ),
    typography: (
      menu-item-label-text-font: map.get($system, body-large-font),
      menu-item-label-text-size: map.get($system, body-large-size),
      menu-item-label-text-tracking: map.get($system, body-large-tracking),
      menu-item-label-text-line-height: map.get($system, body-large-line-height),
      menu-item-label-text-weight: map.get($system, body-large-weight),
    ),
    density: (),
  );
}

@use 'sass:map';
@use '../core/theming/theming';
@use '../core/tokens/m2-utils';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);
  $density-scale: theming.clamp-density(map.get($system, density-scale), -3);

  @return (
    base: (),
    color: private-get-color-palette-color-tokens(
        map.get($system, surface), map.get($system, on-surface)),
    typography: (
      toolbar-title-text-font: map.get($system, title-small-font),
      toolbar-title-text-line-height: map.get($system, title-small-line-height),
      toolbar-title-text-size: map.get($system, title-small-size),
      toolbar-title-text-tracking: map.get($system, title-small-tracking),
      toolbar-title-text-weight: map.get($system, title-small-weight),
    ),
    density: (
      toolbar-standard-height: map.get((
        0: 64px,
        -1: 60px,
        -2: 56px,
        -3: 52px,
      ), $density-scale),
      toolbar-mobile-height: map.get((
        0: 56px,
        -1: 52px,
        -2: 48px,
        -3: 44px,
      ), $density-scale),
    ),
  );
}

// Generates the tokens used to theme the toolbar based on a palette.
@function private-get-color-palette-color-tokens($background-color, $text-color) {
  @return (
    toolbar-container-background-color: $background-color,
    toolbar-container-text-color: $text-color,
  );
}

//
// Component: Table
//

.table {
  &:not(.table-dark) {
    color: inherit;
  }

  // fixed table head
  // Uses Bootstrap CSS variables so the sticky header follows light/dark mode
  // automatically. Fixes #6026.
  &.table-head-fixed {
    thead tr:nth-child(1) th {
      position: sticky;
      top: 0;
      z-index: 10;
      background-color: var(--bs-body-bg, #{$white});
      border-bottom: 0;
      box-shadow: inset 0 1px 0 var(--bs-border-color, #{$table-border-color}), inset 0 -1px 0 var(--bs-border-color, #{$table-border-color});
    }
  }

  // no border
  &.no-border {
    &,
    td,
    th {
      border: 0;
    }
  }

  // .text-center in tables
  &.text-center {
    &,
    td,
    th {
      text-align: center;
    }
  }

  &.table-valign-middle {
    thead > tr > th,
    thead > tr > td,
    tbody > tr > th,
    tbody > tr > td {
      vertical-align: middle;
    }
  }

  .card-body.p-0 & {
    thead > tr > th,
    thead > tr > td,
    tfoot > tr > th,
    tfoot > tr > td,
    tbody > tr > th,
    tbody > tr > td {
      &:first-of-type {
        padding-left: map-get($spacers, 4);
      }

      &:last-of-type {
        padding-right: map-get($spacers, 4);
      }
    }
  }
}

@import "./radio";
@import "./radio.ios.vars";

// iOS Radio
// --------------------------------------------------

:host {
  --color-checked: #{ion-color(primary, base)};
}

:host(.ion-color.radio-checked) .radio-inner {
  border-color: current-color(base);
}

.item-radio.item-ios ion-label {
  @include margin-horizontal(0, null);
}

// iOS Radio Checkmark: Checked
// -----------------------------------------

.radio-inner {
  width: 33%;
  height: 50%;
}

:host(.radio-checked) .radio-inner {
  transform: rotate(45deg);

  border-width: $radio-ios-icon-border-width;
  border-top-width: 0;
  border-left-width: 0;
  border-style: $radio-ios-icon-border-style;
  border-color: var(--color-checked);
}

// iOS Radio: Disabled
// -----------------------------------------
// The radio and label should use the
// same opacity and match the other form
// controls

:host(.radio-disabled) {
  opacity: $radio-ios-disabled-opacity;
}

// iOS Radio: Keyboard Focus
// -----------------------------------------

:host(.ion-focused) .radio-icon::after {
  @include border-radius(var(--inner-border-radius));
  @include position(-8px, null, null, -9px);

  display: block;
  position: absolute;

  width: 36px;
  height: 36px;

  background: $radio-ios-background-color-focused;

  content: "";
  opacity: 0.2;
}

// Radio Native Wrapper
// ----------------------------------------------------------------

.native-wrapper .radio-icon {
  width: $radio-ios-icon-width;
  height: $radio-ios-icon-height;
}

@import "./toolbar";
@import "./toolbar.md.vars";

// Material Design Toolbar
// --------------------------------------------------

:host {
  --background: #{$toolbar-md-background};
  --color: #{$toolbar-md-color};
  --border-color: #{$toolbar-md-border-color};
  --padding-top: 0;
  --padding-bottom: 0;
  --padding-start: 0;
  --padding-end: 0;
  --min-height: 56px;
}


// Toolbar: Content
// --------------------------------------------------

.toolbar-content {
  flex: 1;
  order: map-get($toolbar-order-md, content);

  min-width: 0;
  max-width: 100%;
}

// Material Design Toolbar Buttons
// --------------------------------------------------

// Style the first slot with additional margin start
// this only ever gets added to the first start slot buttons
::slotted(.buttons-first-slot) {
  @include margin-horizontal(4px, null);
}

// Style the last slot with additional margin end
// this is added to the end, primary, or secondary slot
// whichever it finds first, and the first one it finds
// if multiple of the same name are found
::slotted(.buttons-last-slot) {
  @include margin-horizontal(null, 4px);
}


// Material Design Toolbar Slot Placement
// --------------------------------------------------

::slotted([slot="start"]) {
  order: map-get($toolbar-order-md, slot-start);
}

::slotted([slot="secondary"]) {
  order: map-get($toolbar-order-md, slot-secondary);
}

::slotted([slot="primary"]) {
  order: map-get($toolbar-order-md, slot-primary);

  text-align: end;
}

::slotted([slot="end"]) {
  order: map-get($toolbar-order-md, slot-end);

  text-align: end;
}

@use '@material/theme/theme-color';
@use '@material/density/variables' as density-variables;

$ripple-target: '.mdc-list-item__ripple';
$divider-color-on-light-bg: rgba(0, 0, 0, 0.12) !default;
$divider-color-on-dark-bg: rgba(255, 255, 255, 0.2) !default;
$content-disabled-opacity: theme-color.text-emphasis(disabled) !default;
$content-disabled-color: on-surface !default;
$content-selected-color: primary !default;
$side-padding: 16px !default;

$one-line-item-density-scale: density-variables.$default-scale !default;
$two-line-item-density-scale: density-variables.$default-scale !default;
$three-line-item-density-scale: density-variables.$default-scale !default;
$one-line-item-density-config: (
  height: (
    default: 48px,
    maximum: 48px,
    minimum: 24px,
  ),
) !default;
$one-line-item-tall-density-config: (
  height: (
    default: 56px,
    maximum: 56px,
    minimum: 40px,
  ),
) !default;
$one-line-item-taller-density-config: (
  height: (
    default: 72px,
    maximum: 72px,
    minimum: 56px,
  ),
) !default;
$two-line-item-density-config: (
  height: (
    default: 64px,
    maximum: 64px,
    minimum: 48px,
  ),
) !default;
$two-line-item-tall-density-config: (
  height: (
    default: 72px,
    maximum: 72px,
    minimum: 56px,
  ),
) !default;
$two-line-item-taller-density-config: (
  height: (
    default: 88px,
    maximum: 88px,
    minimum: 72px,
  ),
) !default;
$three-line-item-density-config: (
  height: (
    default: 88px,
    maximum: 88px,
    minimum: 56px,
  ),
) !default;

//
// Badges
// --------------------------------------------------


// Base class
.badge {
  display: inline-block;
  min-width: 10px;
  padding: 3px 7px;
  font-size: $font-size-small;
  font-weight: $badge-font-weight;
  line-height: $badge-line-height;
  color: $badge-color;
  text-align: center;
  white-space: nowrap;
  vertical-align: middle;
  background-color: $badge-bg;
  border-radius: $badge-border-radius;

  // Empty badges collapse automatically (not available in IE8)
  &:empty {
    display: none;
  }

  // Quick fix for badges in buttons
  .btn & {
    position: relative;
    top: -1px;
  }

  .btn-xs &,
  .btn-group-xs > .btn & {
    top: 0;
    padding: 1px 5px;
  }

  // [converter] extracted a& to a.badge

  // Account for badges in navs
  .list-group-item.active > &,
  .nav-pills > .active > a > & {
    color: $badge-active-color;
    background-color: $badge-active-bg;
  }

  .list-group-item > & {
    float: right;
  }

  .list-group-item > & + & {
    margin-right: 5px;
  }

  .nav-pills > li > a > & {
    margin-left: 3px;
  }
}

// Hover state, but only for links
a.badge {
  &:hover,
  &:focus {
    color: $badge-link-hover-color;
    text-decoration: none;
    cursor: pointer;
  }
}

// Button variants
//
// Easily pump out default styles, as well as :hover, :focus, :active,
// and disabled options for all buttons

@mixin button-variant($color, $background, $border) {
  color: $color;
  background-color: $background;
  border-color: $border;

  &:focus,
  &.focus {
    color: $color;
    background-color: darken($background, 10%);
    border-color: darken($border, 25%);
  }
  &:hover {
    color: $color;
    background-color: darken($background, 10%);
    border-color: darken($border, 12%);
  }
  &:active,
  &.active,
  .open > &.dropdown-toggle {
    color: $color;
    background-color: darken($background, 10%);
    background-image: none;
    border-color: darken($border, 12%);

    &:hover,
    &:focus,
    &.focus {
      color: $color;
      background-color: darken($background, 17%);
      border-color: darken($border, 25%);
    }
  }
  &.disabled,
  &[disabled],
  fieldset[disabled] & {
    &:hover,
    &:focus,
    &.focus {
      background-color: $background;
      border-color: $border;
    }
  }

  .badge {
    color: $background;
    background-color: $color;
  }
}

// Button sizes
@mixin button-size($padding-vertical, $padding-horizontal, $font-size, $line-height, $border-radius) {
  padding: $padding-vertical $padding-horizontal;
  font-size: $font-size;
  line-height: $line-height;
  border-radius: $border-radius;
}

// scss-docs-start caret-mixins
@mixin caret-down($width: $caret-width) {
  border-top: $width solid;
  border-right: $width solid transparent;
  border-bottom: 0;
  border-left: $width solid transparent;
}

@mixin caret-up($width: $caret-width) {
  border-top: 0;
  border-right: $width solid transparent;
  border-bottom: $width solid;
  border-left: $width solid transparent;
}

@mixin caret-end($width: $caret-width) {
  border-top: $width solid transparent;
  border-right: 0;
  border-bottom: $width solid transparent;
  border-left: $width solid;
}

@mixin caret-start($width: $caret-width) {
  border-top: $width solid transparent;
  border-right: $width solid;
  border-bottom: $width solid transparent;
}

@mixin caret(
  $direction: down,
  $width: $caret-width,
  $spacing: $caret-spacing,
  $vertical-align: $caret-vertical-align
) {
  @if $enable-caret {
    &::after {
      display: inline-block;
      margin-left: $spacing;
      vertical-align: $vertical-align;
      content: "";
      @if $direction == down {
        @include caret-down($width);
      } @else if $direction == up {
        @include caret-up($width);
      } @else if $direction == end {
        @include caret-end($width);
      }
    }

    @if $direction == start {
      &::after {
        display: none;
      }

      &::before {
        display: inline-block;
        margin-right: $spacing;
        vertical-align: $vertical-align;
        content: "";
        @include caret-start($width);
      }
    }

    &:empty::after {
      margin-left: 0;
    }
  }
}
// scss-docs-end caret-mixins

@use "../../settings" as *;
@use "../../functions" as *;
@use "../../mixins/utilities" as *;
@use "./typeset" as *;

@mixin display {
  @include typeset(
    "heading",
    $theme-display-font-size,
    $theme-heading-line-height
  );

  font-weight: fw("bold");
}

@mixin h1 {
  @include typeset("heading", $theme-h1-font-size, $theme-heading-line-height);
  font-weight: fw("bold");
}

@mixin h2 {
  @include typeset("heading", $theme-h2-font-size, $theme-heading-line-height);
  font-weight: fw("bold");
}

@mixin h3 {
  @include typeset("heading", $theme-h3-font-size, $theme-heading-line-height);
  font-weight: fw("bold");
}

@mixin h4 {
  @include typeset("heading", $theme-h4-font-size, $theme-heading-line-height);
  font-weight: fw("bold");
}
@mixin h5 {
  @include typeset("heading", $theme-h5-font-size, $theme-heading-line-height);
  font-weight: fw("bold");
}

@mixin h6 {
  @include typeset("body", $theme-h6-font-size, $theme-heading-line-height);
  font-weight: fw("normal");
  letter-spacing: ls("ls-1");
  text-transform: uppercase;
}

@mixin typeset-display {
  @include typeset-heading;
  @include display;
}

@mixin typeset-h1 {
  @include typeset-heading;
  @include h1;
}

@mixin typeset-h2 {
  @include typeset-heading;
  @include h2;
}

@mixin typeset-h3 {
  @include typeset-heading;
  @include h3;
}

@mixin typeset-h4 {
  @include typeset-heading;
  @include h4;
}

@mixin typeset-h5 {
  @include typeset-heading;
  @include h5;
}

@mixin typeset-h6 {
  @include typeset-heading;
  @include h6;
}
